### Implement Logging Plugin with Callbacks in Go

Source: https://context7.com/google/adk-go/llms.txt

This Go code snippet demonstrates how to create and configure a logging plugin using `plugin.New`. It includes various callback functions to intercept and log events at different stages of agent execution, such as before/after runs, on events, before/after model calls, and before tool execution. The plugin also has a `CloseFunc` for cleanup operations.

```go
package main

import (
    "context"
    "fmt"
    "log"
    "os"
    "time"

    "google.golang.org/genai"
    "google.golang.org/adk/agent"
    "google.golang.org/adk/agent/llmagent"
    "google.golang.org/adk/model"
    "google.golang.org/adk/model/gemini"
    "google.golang.org/adk/plugin"
    "google.golang.org/adk/runner"
    "google.golang.org/adk/session"
    "google.golang.org/adk/tool"
)

func main() {
    ctx := context.Background()

    modelInstance, _ := gemini.NewModel(ctx, "gemini-2.5-flash", &genai.ClientConfig{
        APIKey: os.Getenv("GOOGLE_API_KEY"),
    })

    // Create a logging plugin
    loggingPlugin, _ := plugin.New(plugin.Config{
        Name: "logging_plugin",

        // Called before each agent run
        BeforeRunCallback: func(ctx agent.InvocationContext) (*genai.Content, error) {
            fmt.Printf("[%s] Starting run for session: %s\n",
                time.Now().Format(time.RFC3339), ctx.Session().ID())
            return nil, nil // Return nil to continue execution
        },

        // Called after each agent run
        AfterRunCallback: func(ctx agent.InvocationContext) {
            fmt.Printf("[%s] Run completed\n", time.Now().Format(time.RFC3339))
        },

        // Called on each event
        OnEventCallback: func(ctx agent.InvocationContext, event *session.Event) (*session.Event, error) {
            fmt.Printf("[Event] Author: %s, ID: %s\n", event.Author, event.ID)
            return event, nil // Return modified or original event
        },

        // Called before model invocation
        BeforeModelCallback: func(ctx agent.CallbackContext, req *model.LLMRequest) (*model.LLMResponse, error) {
            fmt.Printf("[Model] Request with %d contents\n", len(req.Contents))
            return nil, nil // Return nil to proceed with model call
        },

        // Called after model response
        AfterModelCallback: func(ctx agent.CallbackContext, resp *model.LLMResponse, err error) (*model.LLMResponse, error) {
            if resp != nil && resp.UsageMetadata != nil {
                fmt.Printf("[Model] Tokens used: %d\n", resp.UsageMetadata.TotalTokenCount)
            }
            return resp, err
        },

        // Called before tool execution
        BeforeToolCallback: func(ctx tool.Context, t tool.Tool, args map[string]any) (map[string]any, error) {
            fmt.Printf("[Tool] Calling: %s with args: %v\n", t.Name(), args)
            return nil, nil // Return nil to proceed with tool call
        },

        // Cleanup function called when plugin is closed
        CloseFunc: func() error {
            fmt.Println("Plugin cleanup completed")
            return nil
        },
    })

    myAgent, _ := llmagent.New(llmagent.Config{
        Name:        "monitored_agent",
        Model:       modelInstance,
        Description: "Agent with monitoring",
        Instruction: "You are a helpful assistant.",
    })

    sessionService := session.InMemoryService()

    // Create runner with plugin
    r, _ := runner.New(runner.Config{
        AppName:        "my_app",
        Agent:          myAgent,
        SessionService: sessionService,
        PluginConfig: runner.PluginConfig{
            Plugins:      []*plugin.Plugin{loggingPlugin},
            CloseTimeout: 5 * time.Second,
        },
    })

    sessResp, _ := sessionService.Create(ctx, &session.CreateRequest{
        AppName: "my_app",
        UserID:  "user123",
    })

    userMsg := genai.NewContentFromText("Hello!", genai.RoleUser)
    for event, _ := range r.Run(ctx, "user123", sessResp.Session.ID(), userMsg, agent.RunConfig{}) {
        if event != nil && event.Content != nil {
            for _, part := range event.Content.Parts {
                if part.Text != "" {
                    fmt.Printf("Response: %s\n", part.Text)
                }
            }
        }
    }
}

```

