### Implement LLM Agent Callbacks in Go

Source: https://context7.com/google/adk-go/llms.txt

This Go code demonstrates how to implement BeforeModel, AfterModel, and OnModelError callbacks for an LLM agent. The BeforeModel callback checks a cache, the AfterModel callback logs token usage and caches the response, and the OnModelError callback handles model errors. It requires the 'google.golang.org/genai' and 'google.golang.org/adk' packages.

```go
package main

import (
    "context"
    "encoding/json"
    "fmt"
    "log"
    "os"

    "google.golang.org/genai"
    "google.golang.org/adk/agent"
    "google.golang.org/adk/agent/llmagent"
    "google.golang.org/adk/cmd/launcher"
    "google.golang.org/adk/cmd/launcher/full"
    "google.golang.org/adk/model"
    "google.golang.org/adk/model/gemini"
)

// Simple cache for demonstration
var responseCache = make(map[string]*model.LLMResponse)

func main() {
    ctx := context.Background()

    modelInstance, _ := gemini.NewModel(ctx, "gemini-2.5-flash", &genai.ClientConfig{
        APIKey: os.Getenv("GOOGLE_API_KEY"),
    })

    myAgent, _ := llmagent.New(llmagent.Config{
        Name:        "cached_agent",
        Model:       modelInstance,
        Description: "Agent with caching",
        Instruction: "You are a helpful assistant.",

        // Before model callback - can skip model call by returning response
        BeforeModelCallbacks: []llmagent.BeforeModelCallback{
            func(ctx agent.CallbackContext, req *model.LLMRequest) (*model.LLMResponse, error) {
                // Create cache key from request
                key := fmt.Sprintf("%v", req.Contents)

                // Check cache
                if cached, ok := responseCache[key]; ok {
                    fmt.Println("Cache hit! Returning cached response.")
                    return cached, nil // Skip model call
                }

                fmt.Println("Cache miss, calling model...")
                return nil, nil // Proceed with model call
            },
        },

        // After model callback - can modify response
        AfterModelCallbacks: []llmagent.AfterModelCallback{
            func(ctx agent.CallbackContext, resp *model.LLMResponse, err error) (*model.LLMResponse, error) {
                if err != nil {
                    return resp, err
                }

                // Log token usage
                if resp.UsageMetadata != nil {
                    fmt.Printf("Tokens - Prompt: %d, Response: %d, Total: %d\n",
                        resp.UsageMetadata.PromptTokenCount,
                        resp.UsageMetadata.CandidatesTokenCount,
                        resp.UsageMetadata.TotalTokenCount)
                }

                // Cache the response
                reqBytes, _ := json.Marshal(ctx.UserContent())
                responseCache[string(reqBytes)] = resp

                return resp, nil
            },
        },

        // Error callback - handle model errors
        OnModelErrorCallbacks: []llmagent.OnModelErrorCallback{
            func(ctx agent.CallbackContext, req *model.LLMRequest, err error) (*model.LLMResponse, error) {
                fmt.Printf("Model error occurred: %v\n", err)
                // Could return fallback response or retry logic
                return nil, err // Propagate error
            },
        },
    })

    config := &launcher.Config{
        AgentLoader: agent.NewSingleLoader(myAgent),
    }

    l := full.NewLauncher()
    if err := l.Execute(ctx, config, os.Args[1:]); err != nil {
        log.Fatalf("Run failed: %v\n\n%s", err, l.CommandLineSyntax())
    }
}

