    84→func (p *loggingPlugin) formatContent(content *genai.Content, maxLength int) string {
    85→	if content == nil || len(content.Parts) == 0 {
    86→		return "None"
    87→	}
    88→
    89→	var parts []string
    90→	for _, part := range content.Parts {
    91→		if part.Text != "" {
    92→			text := strings.TrimSpace(part.Text)
    93→			if len(text) > maxLength {
    94→				text = text[:maxLength] + "..."
    95→			}
    96→			parts = append(parts, fmt.Sprintf("text: '%s'", text))
    97→		} else if part.FunctionCall != nil {
    98→			parts = append(parts, fmt.Sprintf("function_call: %s", part.FunctionCall.Name))
    99→		} else if part.FunctionResponse != nil {
   100→			parts = append(parts, fmt.Sprintf("function_response: %s", part.FunctionResponse.Name))
   101→		} else if part.CodeExecutionResult != nil {
   102→			parts = append(parts, "code_execution_result")
   103→		} else {
   104→			parts = append(parts, "other_part")
   105→		}
   106→	}
   107→	return strings.Join(parts, " | ")
   108→}
